import Amplify, { API, graphqlOperation } from "aws-amplify";
import * as gql from './appsync-gql'

export default {
  async getListings (hostId) {
    return await API.graphql(
        graphqlOperation(
          gql.getListings, { hostId: hostId }
        )
      )
      .catch(e => {
        console.error('getListings error!', e)
        return e
      })
  },
  async createListing (params) {
    params.lastUpdateOn = (new Date).toISOString()

    return await API.graphql(graphqlOperation(gql.createListing, params))
      .catch(e => {
        console.error('createListing', e)
        return e
      })
  },
  async updateListing (params) {
    params.expectedLastUpdateOn = params.lastUpdateOn
    params.lastUpdateOn = (new Date).toISOString()

    return await API.graphql(graphqlOperation(gql.updateListing, params))
      .catch(e => {
        console.error('updateListing', e)
        return e
      })
  },
  async getReservations (listingId) {
    return await API.graphql(
        graphqlOperation(
          gql.getReservations, { listingId: listingId }
        )
      )
      .catch(e => {
        console.error('getReservations', e)
        return e
      })
  },
  async getReservation (reservationCode, listingId) {
    return await API.graphql(
        graphqlOperation(
          gql.getReservation, { reservationCode: reservationCode, listingId: listingId }
        )
      )
      .catch(e => {
        console.error('getReservation', e)
        return e
      })
  },
  async updateReservation (params) {
    params.expectedLastUpdateOn = params.lastUpdateOn
    params.lastUpdateOn = (new Date).toISOString()

    return await API.graphql(graphqlOperation(gql.updateReservation, params))
      .catch(e => {
        console.error('updateReservation', e)
        return e
      })
  },
  async getMembers (reservationCode) {
    return await API.graphql(
        graphqlOperation(
          gql.getMembers, { reservationCode: reservationCode }
        )
      )
      .catch(e => {
        console.error('getMembers', e)
        return e
      })
  },
  async createMember (params) {
    params.lastUpdateOn = (new Date).toISOString()

    return await API.graphql(graphqlOperation(gql.createMember, params))
      .catch(e => {
        console.error('createMember', e)
        return e
      })
  },
  async updateMember (params) {
    params.expectedLastUpdateOn = params.lastUpdateOn
    params.lastUpdateOn = (new Date).toISOString()

    return await API.graphql(graphqlOperation(gql.updateMember, params))
      .catch(e => {
        console.error('updateMember', e)
        return e
      })
  },
  async generateReservation (params) {
    return await API.graphql(graphqlOperation(gql.generateReservation, params))
      .catch(e => {
        console.error('generateReservation', e)
        return e
      })
  },
}